<template>
  <div class="chart-only-container">
    <AnalysisChart
      :title="''"
      :type="finalChartType"
      :height="height"
      :data="chartData"
      :chart-props="finalChartProps"
      :x-axis-name="finalXAxisName"
      :y-axis-name="finalYAxisName"
      :y-axis2-name="finalYAxis2Name"
      :show-controls="false"
      :theme="theme"
    />
  </div>
</template>

<script>
import AnalysisChart from '@/components/analysis/AnalysisChart.vue'
import Request from '@/utils/request'

export default {
  name: 'AnalysisChartOnly',
  components: {
    AnalysisChart
  },
  props: {
    title: {
      type: String,
      required: true
    },
    height: {
      type: Number,
      default: 170
    },
    theme: {
      type: String,
      default: 'default'
    }
  },
  data() {
    return {
      chartData: []
    }
  },
  computed: {
    // 从 localStorage 的菜单数据中获取对应的菜单项
    currentMenu() {
      try {
        const menuData = JSON.parse(localStorage.getItem('userMenuList') || '[]')
        
        // 递归查找菜单项
        const findMenu = (menus, targetName) => {
          for (const menu of menus) {
            if (menu.name === targetName) {
              return menu
            }
            if (menu.children && menu.children.length > 0) {
              const found = findMenu(menu.children, targetName)
              if (found) {
                return found
              }
            }
          }
          return null
        }
        
        return findMenu(menuData, this.title)
      } catch (error) {
        // 静默处理获取菜单数据失败
        return null
      }
    },
    // 从菜单数据中获取 API 地址
    apiUrl() {
      return this.currentMenu?.path || ''
    },
    // 从菜单数据中获取图表类型
    finalChartType() {
      const chartType = this.currentMenu?.chartType
      return chartType && chartType.trim() !== '' ? chartType : 'bar'
    },
    // 从菜单数据中获取图表颜色
    finalChartProps() {
      const props = {}
      const chartColor = this.currentMenu?.chartColor
      if (chartColor && chartColor.trim() !== '') {
        props.color = chartColor
      } else {
        props.color = '#409EFF'
      }
      return props
    },
    // 从菜单数据中获取表格列配置
    finalTableColumns() {
      const columnName = this.currentMenu?.tableColumnName
      const columnValueOne = this.currentMenu?.tableColumnValueOne
      const columnValueTwo = this.currentMenu?.tableColumnValueTwo
      
      // 判断是否为多值图表类型
      const isMultiValueChart = ['dual-bar', 'dual-line', 'bar-line'].includes(this.finalChartType)
      
      if (isMultiValueChart) {
        // 多值图表类型：name, value1, value2
        if (columnName && columnName.trim() !== '' && 
            columnValueOne && columnValueOne.trim() !== '' && 
            columnValueTwo && columnValueTwo.trim() !== '') {
          return {
            name: columnName,
            value1: columnValueOne,
            value2: columnValueTwo
          }
        }
        // 默认配置
        return { 
          name: '名称', 
          value1: '数值1', 
          value2: '数值2' 
        }
      } else {
        // 单值图表类型：name, value
        if (columnName && columnName.trim() !== '' && 
            columnValueOne && columnValueOne.trim() !== '') {
          return {
            name: columnName,
            value: columnValueOne
          }
        }
        // 默认配置
        return { 
          name: '名称', 
          value: '数值' 
        }
      }
    },
    // 自动从 tableColumns 获取轴名称
    finalXAxisName() {
      if (this.finalChartType === 'horizontal-bar') {
        return this.finalTableColumns.value || ''
      }
      return this.finalTableColumns.name || ''
    },
    finalYAxisName() {
      if (this.finalChartType === 'horizontal-bar') {
        return this.finalTableColumns.name || ''
      }
      return this.finalTableColumns.value1 || ''
    },
    finalYAxis2Name() {
      // 只有多值图表才需要第二个Y轴名称
      const isMultiValueChart = ['dual-bar', 'dual-line', 'bar-line'].includes(this.finalChartType)
      if (isMultiValueChart) {
        return this.finalTableColumns.value2 || ''
      }
      return ''
    }
  },
  created() {
    this.fetchData()
  },
  methods: {
    async fetchData() {
      try {
        if (!this.apiUrl) {
          console.warn('API URL 为空，跳过数据获取')
          return
        }
        
        const res = await Request.get(this.apiUrl)
        if (res.code === '0') {
          const rawData = res.data || []
          // 如果是水平条形图，需要反转数据顺序
          this.chartData = this.finalChartType === 'horizontal-bar' ? [...rawData].reverse() : rawData
        }
      } catch (error) {
        // console.error('获取分析数据失败:', error)
      }
    }
  }
}
</script>

<style scoped>
.chart-only-container {
  width: 100%;
  height: 100%;
}
</style>
