import Vue from 'vue'
import VueRouter from 'vue-router'
import home from '../layout/index.vue';


import Home from '@/views/Home.vue';

import Login from '@/views/Login.vue';
import LRLayout from '@/layout/LRLayout.vue';
import Register from '@/views/Register.vue';
import MenuManager from '@/views/MenuManager.vue';
import ElementUI from "element-ui";
import request from '@/utils/request';

Vue.use(VueRouter)

const routes = [

  {
    path: "/login",
    name: "LRLayout",
    redirect: '/login',  
    component:LRLayout,
    children: [
      {
        path: "/login",
        name: "登录页面",
        component: Login,
      },
      {
        path: "/register",
        name: "注册页面",
        component: Register
      },
    ]
  },
  {
    path: '/',
    redirect: '/home',
    name: '主页',
    // component: Home
  },
  {
    path: '/404',
    name: '页面丢失',
    component: () => import('../views/404.vue')
  },
  {
    id: 999,
    path: '/dashboard-fullscreen',
    name: '数据可视化大屏',
    component: () => import('../views/DashboardFullscreen.vue'),
    meta: { title: "数据大屏" }
  },
  {
    id: 998,
    path: '/chat-fullscreen',
    name: '智能助手大屏',
    component: () => import('../views/ChatFullscreen.vue'),
    meta: { title: "智能助手" }
  },
];



const router = new VueRouter({
  mode: "history",
  base: process.env.BASE_URL,
  routes,
});
export const setRoutes = () => {
  const userMenuListStr = localStorage.getItem("userMenuList")
  if (userMenuListStr && userMenuListStr !== 'undefined') {
    const currentRoutes = router.getRoutes().map(v => v.name)
    if (!currentRoutes.includes('Layout')) {
      const currRouter = {
        path: '/',
        name: 'home',
        component: home,
        redirect: '/home',
        children: [
          {
            path: "/home",
            name: "Home",
            component: Home,
            meta: {
              title: "首页"
            },
          },
          {
            path: '/menu',
            name: 'MenuManager',
            component: MenuManager,
            meta: {
              title: "菜单管理"
            },
          },
        ]
      }
      try {
      const menus = JSON.parse(userMenuListStr);
      menus.forEach((item) => {
        if (item.path) {
          const itemMenu = {
            path: item.path.replace("/", ""),
            name: item.name,
            component: () => import(`../views/${item.pagePath}.vue`),
              meta: {
                title: item.name
            }
          };
          currRouter.children.push(itemMenu);
        } else if (item.children?.length) {
          item.children.forEach((item) => {
            if (item.path) {
              const itemMenu = {
                path: item.path.replace("/", ""),
                name: item.name,
                component: () => import(`../views/${item.pagePath}.vue`),
                  meta: {
                    title: item.name
                }
              };
              currRouter.children.push(itemMenu);
            }
          });
        }
      });
      router.addRoute(currRouter)
      } catch (err) {
        // 静默处理解析用户菜单列表失败
    }
  }
  }
}
setRoutes()
router.onError((error) => {
  if (error.message.includes('Cannot find module')) {
    // 如果错误是因为找不到模块，跳转到404页面
    router.replace('/404');
  }
});
router.beforeEach((to, from, next) => {
  if (to.name) {
    localStorage.setItem('currentPathName', to.name);
  }
  // store.commit('setPath')
  const localMenus = localStorage.getItem("userMenuList");
  // console.log(localMenus)
  if (!to.matched.length) {
    if (localMenus) {
      next('/404')
    } else {
      ElementUI.Message({
        message: '请先登录',
        type: 'warning'
      });
      next('/login')
    }
      // eslint-disable-next-line no-empty
  } else { }
  next();
})

// 记录页面访问日志
router.afterEach((to, from) => {
  // 排除登录页面和注册页面（未登录状态，无法记录用户信息）
  if (to.path === '/login' || to.path === '/register') {
    return;
  }
  
  // 获取用户信息
  const userInfoStr = localStorage.getItem('userInfo');
  if (!userInfoStr) {
    return; // 未登录用户不记录
  }
  
  try {
    const userInfo = JSON.parse(userInfoStr);
    if (!userInfo || !userInfo.id) {
      return; // 用户信息不完整
    }
    
    // 发送路由的 path，后端会用这个 path 去菜单表匹配获取页面名称
    const routePath = to.path;
    
    // 构建日志数据
    const actionLog = {
      userId: userInfo.id,
      username: userInfo.username || userInfo.name,
      pageName: null, // 不设置页面名称，让后端通过 requestUrl（路由path）去菜单表匹配
      action: 'VIEW',
      actionDesc: `访问页面: ${routePath}`,
      requestMethod: 'GET',
      requestUrl: routePath // 发送路由路径，用于匹配菜单表
    };
    
    // 异步记录页面访问，不阻塞路由跳转，静默处理错误
    request.post('/actionLog/recordPageView', actionLog).catch(() => {
      // 静默处理错误，不影响用户体验
    });
  } catch (error) {
    // 静默处理错误
    console.debug('记录页面访问日志失败:', error);
  }
})
const originalPush = VueRouter.prototype.push
   VueRouter.prototype.push = function push(location) {
   return originalPush.call(this, location).catch(err => err)
}

export default router;
