<script setup>
import '../assets/iconfont.css';

</script>
<template>
    <div>
        <el-menu
            ref="menu"
            :default-active="$route.path"
            class="el-menu-vertical"
            :collapse-transition="false"
            background-color="transparent"
            text-color="#606266"
            active-text-color="#fff"
            @select="handleMenuSelect">

            <div v-for="item in userMenuList" :key="item.id">
                <div v-if="item.path">
                    <div v-if="!item.pid">
                        <el-menu-item 
                            :index="item.path"
                        >
                            <i :class="getIconClass(item.icon)"></i>
                            <span>{{ item.name }}</span>
                        </el-menu-item>
                    </div>
                </div>
                <div v-else>
                    <el-submenu :index="String(item.id)">
                        <template slot="title">
                            <i :class="getIconClass(item.icon)"></i>
                            <span>{{ item.name }}</span>
                        </template>
                        <div v-for="subItem in item.children" :key="subItem.id">
                            <el-menu-item :index="subItem.path">
                                <i :class="getIconClass(subItem.icon)"></i>
                                <span>{{ subItem.name }}</span>
                            </el-menu-item> 
                        </div>
                    </el-submenu>
                </div>
            </div>
        </el-menu>
    </div>
</template>

<script>


import {setRoutes} from "@/router";
import Request from '../utils/request.js'
import { getIconByKey } from '../utils/iconMapping.js'

export default {
    name: 'AsideMenu',
    components: {},
    // 用户信息
    userInfo: {},
    created() {
        let userMenuListStr = localStorage.getItem("userMenuList")
        this.userMenuList = userMenuListStr ? JSON.parse(userMenuListStr) : [];
        this.userInfo = localStorage.getItem("userInfo") ? JSON.parse(localStorage.getItem("userInfo")) : {};
        // console.log("userMenuList:" + userMenuListStr);
    },
    data() {
        return {
          
            userMenuList: [
                {
                    name: 'Dashboard',
                    path: 'dashboard',
                    icon: 'el-icon-menu'
                },
                {
                    name: 'Reports',
                    path: 'reports',
                    icon: 'el-icon-document',
                    children: [
                        {
                            name: 'Report 1',
                            path: 'report1',
                            icon: 'el-icon-document'
                        },
                        {
                            name: 'Report 2',
                            path: 'report2',
                            icon: 'el-icon-document'
                        }
                    ]
                },
                // 更多静态菜单项...
            ],
            user: {},
            path: this.$route.path
        }
    },
    methods: {
        // 判断是否是全屏页面（需要在新窗口打开）
        isFullscreenPage(item) {
            if (!item) return false
            return item.path === '/dashboard-fullscreen' || 
                   item.path === '/chat-fullscreen'
        },
        // 根据图标key获取对应的图标类
        getIconClass(iconKey) {
            if (!iconKey) return 'el-icon-menu'
            return getIconByKey(iconKey)
        },
        printMenu(menu) {
            // console.log("Submenu:" + menu)
        },
        refreshMenu(){
            Request.get("/menu/getMenuTree/"+this.userInfo.id).then(response => {
                if (response.code === '0') {
                    localStorage.setItem("userMenuList", JSON.stringify(response.data))
                    setRoutes();
         
                } else {
                    this.$message({
                        type: 'error',
                        message: response.msg
                    })
                }
            })
        },
        
        // 处理菜单选择事件（手动控制路由跳转）
        handleMenuSelect(index, indexPath) {
            // 如果 index 是纯数字字符串（可能是子菜单的 id），则忽略，因为子菜单本身不应该触发路由跳转
            // 只有子菜单项（有 path 的菜单项）才会触发路由跳转
            if (index && /^\d+$/.test(index)) {
                // 这是子菜单的 id，不应该触发路由跳转
                return
            }
            
            // 查找对应的菜单项
            const menuItem = this.findMenuItemByPath(this.userMenuList, index)
            
            if (menuItem && this.isFullscreenPage(menuItem)) {
                // 全屏页面：新标签页打开，不进行路由跳转
                const fullscreenUrl = menuItem.path
                window.open(fullscreenUrl, '_blank')
                
                // 保持当前页面的菜单激活状态
                this.$nextTick(() => {
                    // 强制更新菜单的激活状态为当前路由
                    if (this.$refs.menu) {
                        this.$refs.menu.activeIndex = this.$route.path
                    }
                })
                return false
            }
            
            // 其他菜单项：正常路由跳转（index 应该是路径字符串）
            if (index && typeof index === 'string' && !/^\d+$/.test(index) && this.$route.path !== index) {
                this.$router.push(index).catch(err => {
                    // 忽略重复导航错误
                    if (err.name !== 'NavigationDuplicated') {
                        console.error(err)
                    }
                })
            }
        },
        
        // 根据路径查找菜单项
        findMenuItemByPath(menuList, path) {
            for (let item of menuList) {
                if (item.path === path) {
                    return item
                }
                if (item.children && item.children.length > 0) {
                    const found = this.findMenuItemByPath(item.children, path)
                    if (found) return found
                }
            }
            return null
        }
    },
    watch: {
        // 监听路由变化，更新菜单激活状态
        '$route'(to, from) {
            this.$nextTick(() => {
                if (this.$refs.menu) {
                    this.$refs.menu.activeIndex = to.path
                }
            })
        }
    }
}
</script>

